import os
import sys
import argparse
import configparser

try:
    import mysql.connector
except ImportError:
    print("mysql-connector-python is required", file=sys.stderr)
    sys.exit(1)


def read_mysql_config(config_path, section):
    parser = configparser.ConfigParser()
    if not os.path.exists(config_path):
        raise FileNotFoundError(f"Config file not found: {config_path}")
    parser.read(config_path)
    if section not in parser:
        raise KeyError(f"Missing section [{section}] in config")
    cfg = parser[section]
    return {
        "host": cfg.get("host", "localhost"),
        "port": cfg.getint("port", 3306),
        "user": cfg["user"],
        "password": cfg.get("password", ""),
        "database": cfg["database"],
    }


def ensure_local_infile_enabled_in_my_cnf(my_cnf_path):
    if not os.path.exists(my_cnf_path):
        return
    with open(my_cnf_path, "r", encoding="utf-8") as f:
        content = f.read()
    if "local_infile=1" in content or "local-infile=1" in content:
        return
    if "[client]" not in content:
        content += "\n[client]\nlocal_infile=1\n"
    else:
        content += "\nlocal_infile=1\n"
    with open(my_cnf_path, "w", encoding="utf-8") as f:
        f.write(content)


def get_connection(mysql_cfg):
    return mysql.connector.connect(
        host=mysql_cfg["host"],
        port=mysql_cfg["port"],
        user=mysql_cfg["user"],
        password=mysql_cfg["password"],
        database=mysql_cfg["database"],
        allow_local_infile=True,
    )


def build_load_sql(table_name, file_path, columns=None, field_terminator=",", line_terminator="\n", ignore_lines=1):
    cols = f"({', '.join(columns)})" if columns else ""
    sql = "LOAD DATA LOCAL INFILE '{} ' INTO TABLE {}".format(file_path, table_name)
    if cols:
        sql += f" {cols}"
    sql += (
        f" FIELDS TERMINATED BY '{field_terminator}'"
        f" LINES TERMINATED BY '{line_terminator}'"
    )
    if ignore_lines and ignore_lines > 0:
        sql += f" IGNORE {ignore_lines} LINES"
    return sql


def import_file(cursor, table_name, file_path, columns=None):
    if not os.path.exists(file_path):
        raise FileNotFoundError(f"Input file not found: {file_path}")
    sql = build_load_sql(table_name, file_path, columns=columns)
    cursor.execute(sql)


def main():
    parser = argparse.ArgumentParser(description="Bulk import files into MySQL using LOAD DATA INFILE")
    parser.add_argument("--config", required=True, help="Path to MySQL config INI file")
    parser.add_argument("--my-cnf", default=os.path.expanduser("~/.my.cnf"), help="Path to MySQL client config file")
    parser.add_argument("--table", required=True, help="Target MySQL table")
    parser.add_argument("--columns", default="", help="Comma-separated list of target columns")
    parser.add_argument("files", nargs="+", help="One or more file paths to import")
    args = parser.parse_args()

    ensure_local_infile_enabled_in_my_cnf(args.my_cnf)
    mysql_cfg = read_mysql_config(args.config, "mysql")

    columns = [c.strip() for c in args.columns.split(",") if c.strip()] if args.columns else None

    conn = get_connection(mysql_cfg)
